import{c as e,Q as t,j as o,m as r}from"./chunks/framework.Bj0Eefkv.js";const m=JSON.parse('{"title":"Requisitos de Hardware — Gas Station / Liquor Store","description":"","frontmatter":{},"headers":[],"relativePath":"gas-station/local/requisitos-hardware.md","filePath":"gas-station/local/requisitos-hardware.md","lastUpdated":1784247694000}'),d={name:"gas-station/local/requisitos-hardware.md"};function s(i,a,n,l,c,h){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="requisitos-de-hardware-—-gas-station-liquor-store" tabindex="-1">Requisitos de Hardware — Gas Station / Liquor Store <a class="header-anchor" href="#requisitos-de-hardware-—-gas-station-liquor-store" aria-label="Permalink to &quot;Requisitos de Hardware — Gas Station / Liquor Store&quot;">​</a></h1><p><strong>Sistema:</strong> Desbravador Gas Station / Liquor Store<br><strong>Modalidade:</strong> Instalação Local (On-Premise)<br><strong>Público:</strong> Cliente / Fornecedor de hardware / Equipe de TI</p><hr><h2 id="historico-de-revisoes" tabindex="-1">Histórico de Revisões <a class="header-anchor" href="#historico-de-revisoes" aria-label="Permalink to &quot;Histórico de Revisões&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Versão</th><th>Data</th><th>Descrição</th><th>Responsável</th></tr></thead><tbody><tr><td>1.0</td><td>Abr/2023</td><td>Criação do documento</td><td>Andressa Celant</td></tr><tr><td>1.1</td><td>Jul/2024</td><td>Atualização</td><td>Andressa Celant</td></tr><tr><td>1.2</td><td>Mai/2026</td><td>Atualização tecnológica</td><td>Desbravador Software Ltda.</td></tr></tbody></table><hr><h2 id="_1-objetivo" tabindex="-1">1. Objetivo <a class="header-anchor" href="#_1-objetivo" aria-label="Permalink to &quot;1. Objetivo&quot;">​</a></h2><p>Este documento serve como guia para a preparação do ambiente de funcionamento do sistema Desbravador Gas Station e Gas Station 10 (Liquor Store), abordando os requisitos técnicos de instalação e outras questões relacionadas.</p><p>Este descritivo pode ser repassado ao fornecedor de hardware selecionado e servirá como guia para a aquisição dos equipamentos. Os requisitos levam em consideração que os servidores serão utilizados exclusivamente pelos serviços relacionados ao Gas Station. Caso seja necessário compartilhar servidores com outros serviços ou softwares, os requisitos dos demais serviços devem ser considerados no dimensionamento.</p><hr><h2 id="_2-responsabilidades" tabindex="-1">2. Responsabilidades <a class="header-anchor" href="#_2-responsabilidades" aria-label="Permalink to &quot;2. Responsabilidades&quot;">​</a></h2><h3 id="_2-1-desbravador-software-ltda" tabindex="-1">2.1 Desbravador Software Ltda. <a class="header-anchor" href="#_2-1-desbravador-software-ltda" aria-label="Permalink to &quot;2.1 Desbravador Software Ltda.&quot;">​</a></h3><ul><li>A instalação do software do servidor é realizada exclusivamente pelo Analista de Implantação da Desbravador.</li><li>A equipe Desbravador estará disponível para esclarecer dúvidas técnicas durante todo o período de implantação.</li></ul><h3 id="_2-2-cliente-licenciado" tabindex="-1">2.2 Cliente (LICENCIADO) <a class="header-anchor" href="#_2-2-cliente-licenciado" aria-label="Permalink to &quot;2.2 Cliente (LICENCIADO)&quot;">​</a></h3><ul><li>Providenciar os equipamentos conforme especificações deste documento, com sistema operacional previamente instalado e configurado.</li><li>Garantir o licenciamento dos sistemas operacionais e softwares adicionais utilizados.</li><li>Prover segurança física e lógica para servidores e estações de trabalho.</li><li>Disponibilizar técnico de hardware durante o período de implantação.</li><li>Garantir a instalação e configuração de periféricos (impressoras fiscais, concentradoras, medidores de tanque) para as devidas integrações.</li><li>Realizar e manter rotinas de backup dos dados do sistema.</li></ul><blockquote><p>⚠️ <strong>Atenção</strong></p><ul><li>A Desbravador <strong>NÃO</strong> realiza montagem/desmontagem de hardware nem instalação de sistemas operacionais.</li><li>A segurança dos arquivos e dados do sistema é responsabilidade exclusiva de quem opera o sistema.</li><li>Operações indevidas, falhas nas rotinas de backup ou uso de mídia defeituosa são de responsabilidade do LICENCIADO.</li></ul></blockquote><hr><h2 id="_3-selecao-do-fornecedor-de-hardware" tabindex="-1">3. Seleção do Fornecedor de Hardware <a class="header-anchor" href="#_3-selecao-do-fornecedor-de-hardware" aria-label="Permalink to &quot;3. Seleção do Fornecedor de Hardware&quot;">​</a></h2><p>Ao selecionar o fornecedor de equipamentos, certifique-se de que ele oferece:</p><ul><li>Suporte técnico disponível 24 horas por dia.</li><li>Presença física na mesma cidade ou região próxima ao estabelecimento.</li><li>Garantia e assistência técnica dos equipamentos fornecidos.</li><li>Capacidade de assumir responsabilidade pelo sistema operacional, rede e banco de dados.</li><li>Referências de clientes e instalações anteriores verificáveis.</li></ul><hr><h2 id="_4-configuracoes-de-servidor-por-quantidade-de-usuarios" tabindex="-1">4. Configurações de Servidor por Quantidade de Usuários <a class="header-anchor" href="#_4-configuracoes-de-servidor-por-quantidade-de-usuarios" aria-label="Permalink to &quot;4. Configurações de Servidor por Quantidade de Usuários&quot;">​</a></h2><hr><h3 id="_4-1-ate-5-usuarios" tabindex="-1">4.1 Até 5 Usuários <a class="header-anchor" href="#_4-1-ate-5-usuarios" aria-label="Permalink to &quot;4.1 Até 5 Usuários&quot;">​</a></h3><blockquote><p>ℹ️ Nesta faixa, aplicação e banco de dados podem coexistir em um único servidor.</p></blockquote><table tabindex="0"><thead><tr><th>Campo</th><th>Especificação</th></tr></thead><tbody><tr><td><strong>Processador</strong></td><td>Intel Core i5 12ª geração ou superior · AMD Ryzen 5 5600 ou superior</td></tr><tr><td><strong>Memória RAM</strong></td><td>8 GB</td></tr><tr><td><strong>Armazenamento</strong></td><td>SSD 500 GB — obrigatório</td></tr><tr><td><strong>Sistema Operacional</strong></td><td>Microsoft Windows Server 2022 licenciado</td></tr><tr><td><strong>Banco de Dados</strong></td><td>PostgreSQL 16</td></tr></tbody></table><hr><h3 id="_4-2-de-6-a-10-usuarios" tabindex="-1">4.2 De 6 a 10 Usuários <a class="header-anchor" href="#_4-2-de-6-a-10-usuarios" aria-label="Permalink to &quot;4.2 De 6 a 10 Usuários&quot;">​</a></h3><blockquote><p>ℹ️ O uso de dois servidores separados é recomendado para melhor desempenho.</p></blockquote><h4 id="▸-servidor-de-aplicacao" tabindex="-1">▸ Servidor de Aplicação <a class="header-anchor" href="#▸-servidor-de-aplicacao" aria-label="Permalink to &quot;▸ Servidor de Aplicação&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Campo</th><th>Especificação</th></tr></thead><tbody><tr><td><strong>Placa-Mãe</strong></td><td>Compatível com expansão de memória RAM. Marcas de referência: Asus, Intel, MSI, Gigabyte.</td></tr><tr><td><strong>Processador</strong></td><td>Intel Core i5 12ª geração ou superior · AMD Ryzen 5 5600 ou superior</td></tr><tr><td><strong>Memória RAM</strong></td><td>8 GB</td></tr><tr><td><strong>Armazenamento</strong></td><td>SSD 500 GB — obrigatório</td></tr><tr><td><strong>Sistema Operacional</strong></td><td>Microsoft Windows Server 2022 licenciado</td></tr></tbody></table><h4 id="▸-servidor-de-banco-de-dados" tabindex="-1">▸ Servidor de Banco de Dados <a class="header-anchor" href="#▸-servidor-de-banco-de-dados" aria-label="Permalink to &quot;▸ Servidor de Banco de Dados&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Campo</th><th>Especificação</th></tr></thead><tbody><tr><td><strong>Placa-Mãe</strong></td><td>Compatível com expansão de memória RAM. Marcas de referência: Asus, Intel, MSI, Gigabyte.</td></tr><tr><td><strong>Processador</strong></td><td>Intel Core i5 12ª geração ou superior · AMD Ryzen 5 5600 ou superior</td></tr><tr><td><strong>Memória RAM</strong></td><td>8 GB</td></tr><tr><td><strong>Armazenamento</strong></td><td>SSD 1 TB — obrigatório</td></tr><tr><td><strong>Sistema Operacional</strong></td><td>Debian 13</td></tr><tr><td><strong>Banco de Dados</strong></td><td>PostgreSQL 16</td></tr></tbody></table><hr><h3 id="_4-3-de-11-a-20-usuarios" tabindex="-1">4.3 De 11 a 20 Usuários <a class="header-anchor" href="#_4-3-de-11-a-20-usuarios" aria-label="Permalink to &quot;4.3 De 11 a 20 Usuários&quot;">​</a></h3><blockquote><p>⚠️ <strong>Obrigatório</strong> — dois servidores separados (Aplicação e Banco de Dados).</p></blockquote><h4 id="▸-servidor-de-aplicacao-1" tabindex="-1">▸ Servidor de Aplicação <a class="header-anchor" href="#▸-servidor-de-aplicacao-1" aria-label="Permalink to &quot;▸ Servidor de Aplicação&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Campo</th><th>Especificação</th></tr></thead><tbody><tr><td><strong>Placa-Mãe</strong></td><td>Compatível com expansão de memória RAM. Marcas de referência: Asus, Intel, MSI, Gigabyte.</td></tr><tr><td><strong>Processador</strong></td><td>Intel Core i5 12ª geração ou superior · AMD Ryzen 5 5600 ou superior</td></tr><tr><td><strong>Memória RAM</strong></td><td>16 GB</td></tr><tr><td><strong>Armazenamento</strong></td><td>SSD 500 GB — obrigatório</td></tr><tr><td><strong>Sistema Operacional</strong></td><td>Microsoft Windows Server 2022 licenciado</td></tr></tbody></table><h4 id="▸-servidor-de-banco-de-dados-1" tabindex="-1">▸ Servidor de Banco de Dados <a class="header-anchor" href="#▸-servidor-de-banco-de-dados-1" aria-label="Permalink to &quot;▸ Servidor de Banco de Dados&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Campo</th><th>Especificação</th></tr></thead><tbody><tr><td><strong>Placa-Mãe</strong></td><td>Compatível com expansão de memória RAM. Marcas de referência: Asus, Intel, MSI, Gigabyte.</td></tr><tr><td><strong>Processador</strong></td><td>Intel Core i5 12ª geração ou superior · AMD Ryzen 5 5600 ou superior</td></tr><tr><td><strong>Memória RAM</strong></td><td>16 GB</td></tr><tr><td><strong>Armazenamento</strong></td><td>SSD 1 TB — obrigatório</td></tr><tr><td><strong>Sistema Operacional</strong></td><td>Debian 13</td></tr><tr><td><strong>Banco de Dados</strong></td><td>PostgreSQL 16</td></tr></tbody></table><hr><h3 id="_4-4-de-21-a-40-usuarios" tabindex="-1">4.4 De 21 a 40 Usuários <a class="header-anchor" href="#_4-4-de-21-a-40-usuarios" aria-label="Permalink to &quot;4.4 De 21 a 40 Usuários&quot;">​</a></h3><blockquote><p>⚠️ <strong>Obrigatório</strong> — dois servidores separados (Aplicação e Banco de Dados).</p></blockquote><h4 id="▸-servidor-de-aplicacao-2" tabindex="-1">▸ Servidor de Aplicação <a class="header-anchor" href="#▸-servidor-de-aplicacao-2" aria-label="Permalink to &quot;▸ Servidor de Aplicação&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Campo</th><th>Especificação</th></tr></thead><tbody><tr><td><strong>Placa-Mãe</strong></td><td>Compatível com expansão de memória RAM. Marcas de referência: Asus, Intel, MSI, Gigabyte.</td></tr><tr><td><strong>Processador</strong></td><td>Intel Xeon E-2300 ou superior · AMD Ryzen 7 5700 ou superior</td></tr><tr><td><strong>Memória RAM</strong></td><td>32 GB</td></tr><tr><td><strong>Armazenamento</strong></td><td>SSD 500 GB — obrigatório</td></tr><tr><td><strong>Sistema Operacional</strong></td><td>Microsoft Windows Server 2022 licenciado</td></tr></tbody></table><h4 id="▸-servidor-de-banco-de-dados-2" tabindex="-1">▸ Servidor de Banco de Dados <a class="header-anchor" href="#▸-servidor-de-banco-de-dados-2" aria-label="Permalink to &quot;▸ Servidor de Banco de Dados&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Campo</th><th>Especificação</th></tr></thead><tbody><tr><td><strong>Placa-Mãe</strong></td><td>Compatível com expansão de memória RAM. Marcas de referência: Asus, Intel, MSI, Gigabyte.</td></tr><tr><td><strong>Processador</strong></td><td>Intel Xeon E-2300 ou superior · AMD Ryzen 7 5700 ou superior</td></tr><tr><td><strong>Memória RAM</strong></td><td>32 GB</td></tr><tr><td><strong>Armazenamento</strong></td><td>SSD 1 TB — obrigatório, preferencialmente em RAID 1</td></tr><tr><td><strong>Sistema Operacional</strong></td><td>Debian 13</td></tr><tr><td><strong>Banco de Dados</strong></td><td>PostgreSQL 16</td></tr></tbody></table><hr><h3 id="_4-5-acima-de-40-usuarios" tabindex="-1">4.5 Acima de 40 Usuários <a class="header-anchor" href="#_4-5-acima-de-40-usuarios" aria-label="Permalink to &quot;4.5 Acima de 40 Usuários&quot;">​</a></h3><p>Ambientes com mais de 40 usuários simultâneos requerem dimensionamento especializado, considerando volume de transações, número de terminais, integrações e infraestrutura disponível.</p><blockquote><p>ℹ️ Entre em contato com o setor de TI da Desbravador para avaliação e dimensionamento adequado ao seu ambiente. <strong>Desbravador Software Ltda.</strong><br> 🌐 <a href="https://www.desbravador.com.br" target="_blank" rel="noreferrer">www.desbravador.com.br</a></p></blockquote><hr><h2 id="_5-hardwares-complementares-todas-as-configuracoes" tabindex="-1">5. Hardwares Complementares (Todas as Configurações) <a class="header-anchor" href="#_5-hardwares-complementares-todas-as-configuracoes" aria-label="Permalink to &quot;5. Hardwares Complementares (Todas as Configurações)&quot;">​</a></h2><h3 id="_5-1-armazenamento" tabindex="-1">5.1 Armazenamento <a class="header-anchor" href="#_5-1-armazenamento" aria-label="Permalink to &quot;5.1 Armazenamento&quot;">​</a></h3><ul><li>SSD 500 GB para o servidor de aplicação e SSD 1 TB para o servidor de banco de dados (marcas de referência: Samsung, Kingston, WD).</li><li>Servidores com dados de missão crítica devem usar RAID Nível 1 ou 1+0.</li></ul><h3 id="_5-2-dispositivos-de-backup" tabindex="-1">5.2 Dispositivos de Backup <a class="header-anchor" href="#_5-2-dispositivos-de-backup" aria-label="Permalink to &quot;5.2 Dispositivos de Backup&quot;">​</a></h3><ul><li>HD externo, gravador de CD/DVD, Pen Drive, fita ou armazenamento em nuvem (ex.: Google Drive).</li><li><strong>IMPORTANTE:</strong> dispositivos externos de backup devem ser conectados ao servidor apenas no momento da realização do backup.</li><li>Um local de backup externo (nuvem) deve ser configurado pela equipe de TI do cliente para backup completo do banco de dados e arquivos de aplicação.</li></ul><h3 id="_5-3-rede" tabindex="-1">5.3 Rede <a class="header-anchor" href="#_5-3-rede" aria-label="Permalink to &quot;5.3 Rede&quot;">​</a></h3><ul><li><strong>Placa de rede:</strong> Gigabit Ethernet 100/1000 Mbps (pode ser on-board). Marcas de referência: 3COM, Encore, TP-Link.</li><li><strong>Switch:</strong> portas 100/1000 Mbps. Marcas de referência: Dell, HP, 3COM, Encore, TP-Link.</li><li>⚠️ A velocidade de comunicação é limitada pelo componente mais lento — placa de rede e switch devem ter a mesma capacidade.</li><li>Recomenda-se redundância de placa de rede nos servidores.</li></ul><h3 id="_5-4-url-obrigatoria-—-liberacao-em-proxy-firewall-de-saida" tabindex="-1">5.4 URL obrigatória — liberação em proxy/firewall de saída <a class="header-anchor" href="#_5-4-url-obrigatoria-—-liberacao-em-proxy-firewall-de-saida" aria-label="Permalink to &quot;5.4 URL obrigatória — liberação em proxy/firewall de saída&quot;">​</a></h3><blockquote><p>⚠️ O endereço <code>https://servicos.desbravador.com.br/</code> deve estar <strong>permitido (bypass)</strong> em proxies, filtros de conteúdo e firewalls de saída. O bloqueio desta URL impede o funcionamento de serviços essenciais do sistema.</p></blockquote><h3 id="_5-5-protecao-eletrica" tabindex="-1">5.5 Proteção Elétrica <a class="header-anchor" href="#_5-5-protecao-eletrica" aria-label="Permalink to &quot;5.5 Proteção Elétrica&quot;">​</a></h3><ul><li><strong>Nobreak (UPS)</strong> para cada servidor — indispensável para proteger o banco de dados contra quedas de energia.</li></ul><hr><h2 id="_6-estacoes-de-trabalho" tabindex="-1">6. Estações de Trabalho <a class="header-anchor" href="#_6-estacoes-de-trabalho" aria-label="Permalink to &quot;6. Estações de Trabalho&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Componente</th><th>Especificação</th></tr></thead><tbody><tr><td><strong>Processador</strong></td><td>Intel Core i3 10ª geração ou superior · AMD X4 Quad-Core</td></tr><tr><td><strong>Memória RAM</strong></td><td>8 GB</td></tr><tr><td><strong>Armazenamento</strong></td><td>SSD 500 GB</td></tr><tr><td><strong>Placa de Rede</strong></td><td>Gigabit Ethernet 100/1000 Mbps (pode ser on-board)</td></tr><tr><td><strong>Portas Seriais</strong></td><td>Obrigatório para conexão com impressoras fiscais</td></tr><tr><td><strong>Sistema Operacional</strong></td><td>Microsoft Windows 11 (Professional ou Home), licenciado</td></tr><tr><td><strong>Antivírus</strong></td><td>Obrigatório (solução licenciada)</td></tr></tbody></table><hr><h2 id="_7-concentradoras-homologadas" tabindex="-1">7. Concentradoras Homologadas <a class="header-anchor" href="#_7-concentradoras-homologadas" aria-label="Permalink to &quot;7. Concentradoras Homologadas&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Fabricante</th><th>Modelo</th><th>Tipo de Comunicação</th></tr></thead><tbody><tr><td>Companytec</td><td>Company CBC 01</td><td>Serial</td></tr><tr><td>Companytec</td><td>Company CBC 02</td><td>Serial</td></tr><tr><td>Companytec</td><td>Company CBC 03</td><td>Serial</td></tr><tr><td>Companytec</td><td>Company CBC 04</td><td>Serial</td></tr><tr><td>Companytec</td><td>Company CBC 05</td><td>Serial</td></tr><tr><td>Companytec</td><td>Company CBC 06</td><td>Serial e TCP</td></tr><tr><td>Companytec</td><td>Horustech</td><td>Serial e TCP</td></tr><tr><td>Vwtech</td><td>VW Tech / Control Tech</td><td>Serial e TCP</td></tr><tr><td>Wayne</td><td>Fusion</td><td>Serial e TCP</td></tr><tr><td>Hiro</td><td>Hiro</td><td>Serial, USB e TCP</td></tr></tbody></table><blockquote><p>ℹ️ Qualquer equipamento que emule o protocolo Companytec pode ser utilizado com o Gas Station.</p></blockquote><hr><h2 id="_8-medidores-de-tanque-homologados" tabindex="-1">8. Medidores de Tanque Homologados <a class="header-anchor" href="#_8-medidores-de-tanque-homologados" aria-label="Permalink to &quot;8. Medidores de Tanque Homologados&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Fabricante</th><th>Modelos</th><th>Tipo de Comunicação</th></tr></thead><tbody><tr><td>Telemed</td><td>Todos os modelos</td><td>Serial</td></tr><tr><td>Veeder Root</td><td>Todos os modelos</td><td>Serial</td></tr></tbody></table><hr><h2 id="_9-impressoras-fiscais-homologadas" tabindex="-1">9. Impressoras Fiscais Homologadas <a class="header-anchor" href="#_9-impressoras-fiscais-homologadas" aria-label="Permalink to &quot;9. Impressoras Fiscais Homologadas&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Fabricante</th><th>Modelos</th></tr></thead><tbody><tr><td><strong>Daruma</strong></td><td>FS-600, FS-700H, FS-700L, FS-700M, MACH 1, MACH 2, MACH 3</td></tr><tr><td><strong>Elgin</strong></td><td>FIT 1E</td></tr><tr><td><strong>Epson</strong></td><td>TM-88 FB, TM-88 FB II, TM-88 FB III, T81 FB II, T81 FB III, TM-T800F, TM-T900F (Blindada)</td></tr><tr><td><strong>Bematech</strong></td><td>MP-2100 TH FI, MP-2000 TH FI, MP-4000 TH FI, MP-4200 TH FI (Blindada), MP-4200 TH FI II (Blindada), MP-3000 TH FI</td></tr><tr><td><strong>Sweda</strong></td><td>ST120, ST20</td></tr></tbody></table><hr><h2 id="_10-balancas-homologadas" tabindex="-1">10. Balanças Homologadas <a class="header-anchor" href="#_10-balancas-homologadas" aria-label="Permalink to &quot;10. Balanças Homologadas&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Fabricante</th><th>Modelo</th></tr></thead><tbody><tr><td>Filizola</td><td>CS15</td></tr><tr><td>Toledo</td><td>Prix 3</td></tr><tr><td>Toledo</td><td>Prix 5</td></tr></tbody></table><hr><h2 id="_11-perifericos-homologados" tabindex="-1">11. Periféricos Homologados <a class="header-anchor" href="#_11-perifericos-homologados" aria-label="Permalink to &quot;11. Periféricos Homologados&quot;">​</a></h2><p>O sistema possui integração desenvolvida e homologada com os seguintes periféricos:</p><ul><li>💳 <a href="./../../perifericos/pinpads-homologados.html">Pinpads homologados</a></li><li>💳 <a href="./../../perifericos/tef-homologados.html">Sistemas de TEF homologados</a></li><li>🖨️ <a href="./../../perifericos/impressoras-homologadas.html">Impressoras não fiscais homologadas</a></li></ul><hr><h2 id="_12-contato-e-suporte" tabindex="-1">12. Contato e Suporte <a class="header-anchor" href="#_12-contato-e-suporte" aria-label="Permalink to &quot;12. Contato e Suporte&quot;">​</a></h2><p><strong>Desbravador Software Ltda.</strong><br> 🌐 <a href="https://www.desbravador.com.br" target="_blank" rel="noreferrer">www.desbravador.com.br</a></p><p>Para dúvidas técnicas durante a implantação, a equipe Desbravador estará disponível para esclarecimentos.</p>',87)])])}const p=e(d,[["render",s]]);export{m as __pageData,p as default};
